var processedIds = new Set(
  $('IDs Processados').all()
    .map(function(i) { return Number(i.json.glpi_ticket_id); })
    .filter(function(n) { return !isNaN(n) && n > 0; })
);

var todosAtivos = $('Ativos IN_USE').all().map(function(i) { return i.json; });
var sessionToken = $('GLPI initSession').first().json.session_token;

var searchResult = $input.first().json;
var items = Array.isArray(searchResult.data)
  ? searchResult.data
  : Object.values(searchResult.data || {});

var PARTICULAS = new Set(['de','da','do','dos','das','e','em','a','o','um','uma']);

function tokenizar(nome) {
  return (nome || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z\s]/g, '')
    .trim()
    .split(/\s+/)
    .filter(function(w) { return w.length > 1 && !PARTICULAS.has(w); });
}

function scoreSimilaridade(a, b) {
  var ta = tokenizar(a), tb = tokenizar(b);
  if (!ta.length || !tb.length) return 0;
  var setB = new Set(tb);
  return ta.filter(function(t) { return setB.has(t); }).length / Math.max(ta.length, tb.length);
}

function extrairCampo(html, rotulo) {
  var patterns = [
    new RegExp(rotulo + '[^<]*<\/b>\\s*<br\\s*\/?>\\s*([^<]+)', 'i'),
    new RegExp(rotulo + '[^<]*<\/strong>\\s*<br\\s*\/?>\\s*([^<]+)', 'i'),
    new RegExp('<td[^>]*>\\s*' + rotulo + '[^<]*<\/td>\\s*<td[^>]*>\\s*([^<]+)', 'i')
  ];
  for (var i = 0; i < patterns.length; i++) {
    var m = html.match(patterns[i]);
    if (m && m[1].trim()) return m[1].trim().replace(/&nbsp;/g,' ').replace(/&amp;/g,'&').replace(/\s+/g,' ').trim();
  }
  return null;
}

function parsearConteudo(raw) {
  var html = (raw || '').replace(/\r?\n/g, ' ');
  var texto = html.replace(/<[^>]+>/g,' ').replace(/&[^;]+;/g,' ').replace(/\s+/g,' ');
  var nome = extrairCampo(html, 'Nome Completo') || extrairCampo(texto, 'Nome Completo');
  var tipo = extrairCampo(html, 'Tipo de Solicita') || extrairCampo(texto, 'Tipo de Solicita');
  var matr = extrairCampo(html, 'Matr') || extrairCampo(texto, 'Matr');
  var cargo = extrairCampo(html, 'Cargo') || extrairCampo(texto, 'Cargo');
  var login = extrairCampo(html, 'Login para Bloqueio') || extrairCampo(texto, 'Login para Bloqueio');
  if (!nome) {
    var m2 = texto.match(/Nome Completo\s+([A-Za-z\u00C0-\u00FF][a-z\u00C0-\u00FF]+(?:\s+[A-Za-z\u00C0-\u00FF][a-z\u00C0-\u00FF]+)+)/);
    if (m2) nome = m2[1].trim();
  }
  if (!tipo) {
    if (/demiss/i.test(texto)) tipo = 'Demissao';
    else if (/f.rias/i.test(texto)) tipo = 'Ferias';
  }
  return { nome: nome, tipo: tipo || 'Desconhecido', matr: matr || '', cargo: cargo || '', login: login || '' };
}

var SCORE_MIN = 0.5;
var resultados = [];

for (var k = 0; k < items.length; k++) {
  var item = items[k];
  var ticketId = Number(item['1'] || item['id'] || 0);
  if (!ticketId || processedIds.has(ticketId)) continue;

  var content = String(item['21'] || '');
  var parsed = parsearConteudo(content);
  var nome = parsed.nome, tipo = parsed.tipo, matr = parsed.matr, cargo = parsed.cargo, login = parsed.login;
  if (!nome) continue;

  var isDemissao = /demiss/i.test(tipo);

  var matches = isDemissao
    ? todosAtivos
        .map(function(a) { return Object.assign({}, a, { _score: scoreSimilaridade(nome, a.employee_name) }); })
        .filter(function(a) { return a._score >= SCORE_MIN; })
        .sort(function(a, b) { return b._score - a._score; })
    : [];

  var nota = isDemissao
    ? (matches.length > 0
        ? 'AssetAgro: ' + matches.length + ' ativo(s) de ' + nome + ' movidos para STOCK:\n' +
          matches.map(function(a) { return '- ' + a.service_tag + ' (' + (a._score*100).toFixed(0) + '% match)'; }).join('\n')
        : 'AssetAgro: nenhum ativo encontrado para ' + nome + '. Verificar manualmente.')
    : 'AssetAgro: tipo ' + tipo + ' - sem alteracao de ativos.';

  var matchedIdsSql = matches.length > 0
    ? matches.map(function(a) { return "'" + String(a.id).replace(/'/g, '') + "'"; }).join(',')
    : "'00000000-0000-0000-0000-000000000000'";

  resultados.push({
    ticketId: ticketId,
    nome: nome,
    tipo: tipo,
    matr: matr,
    cargo: cargo,
    login: login,
    isDemissao: isDemissao,
    matchedIdsSql: matchedIdsSql,
    sessionToken: sessionToken,
    nota: nota,
    ativos: matches.map(function(a) {
      return { service_tag: a.service_tag, model: a.model, equipment_type: a.equipment_type, score: (a._score*100).toFixed(0)+'%' };
    }),
    temAtivos: matches.length > 0,
    totalAtivos: matches.length
  });
}

return resultados.map(function(r) { return { json: r }; });
